section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/django-celery.json",
  "type": "object",
  "title": "Django + Celery Background Jobs",
  "required": [
    "task_name",
    "business_key",
    "max_retries",
    "backoff_base_seconds",
    "backoff_jitter",
    "dispatch_mode",
    "dlq_queue",
    "alerting_channel"
  ],
  "additionalProperties": false,
  "properties": {
    "task_name": {
      "type": "string",
      "minLength": 1,
      "description": "Dotted path to the task function."
    },
    "business_key": {
      "type": "string",
      "minLength": 1,
      "description": "Name of the idempotency-key argument."
    },
    "max_retries": {
      "type": "integer",
      "description": "Bounded retry count; \u22645."
    },
    "backoff_base_seconds": {
      "type": "integer",
      "description": "Exponential backoff base; \u22651."
    },
    "backoff_jitter": {
      "type": "string",
      "enum": [
        "none",
        "full",
        "equal"
      ],
      "description": "Jitter style."
    },
    "dispatch_mode": {
      "type": "string",
      "enum": [
        "on_commit",
        "outside_transaction"
      ],
      "description": "Where dispatch happens."
    },
    "dlq_queue": {
      "type": "string",
      "minLength": 1,
      "description": "Dead-letter queue name."
    },
    "alerting_channel": {
      "type": "string",
      "minLength": 1,
      "description": "Pager channel for DLQ alerts."
    }
  }
}
